import React, { useEffect, useState } from 'react'
import axios from 'axios'
import Header from '../../../shared/header/Header'

const Home = ({ user }) => {
	let message
	if (user) {
		message = `Hi ${user.first_name} ${user.last_name}`
	} else {
		message = 'You are not logged in'
	}

	return (
		<div>
			<div className="">
				<h1>{message}</h1>
			</div>
		</div>
	)
}

export default Home
